        if (altKey) {
          changes = getChangesOnSelection(props, state.highlightedIndex)
        } else {
          changes = {
            highlightedIndex: getNextWrappingIndex(
              -1,
              state.highlightedIndex,
              props.items.length,
              action.getItemNodeFromIndex,
              true,
            ),
          }
